scripts.test:
node --input-type=module -e '
import { rulesEqual } from "./dist/core.js";
const sample = { naming: { id: "naming", content: "Use camelCase" } };
console.log("Running direct tests...");
console.assert(rulesEqual(sample, { ...sample }), "detects equality");
console.assert(!rulesEqual(sample, { naming: { id: "naming", content: "Use PascalCase" } }), "detects difference");
console.log("✓ All tests passed");
'
